import { PublicKey, SystemProgram } from "@solana/web3.js";
import { config } from "./config.js";
import { executePreparedSwap, prepareSolToCoreSwap, type PreparedSwap } from "./jupiter.js";
import { createAndBurnCorePool, resumeAndBurnCorePool } from "./raydium.js";
import { connection, CurveData, globalPda, program } from "./program.js";
import { StateStore } from "./state.js";

export async function migrateCurve(curvePublicKey: PublicKey, curve: CurveData, store: StateStore): Promise<void> {
  const key = curvePublicKey.toBase58();
  const mint = curve.mint;
  let record = store.get(key) ?? await store.patch(key, { mint: mint.toBase58(), phase: "detected" });

  try {
    if (curve.status === 1) {
      await program.methods.beginMigration().accounts({
        global: globalPda,
        curve: curvePublicKey,
        migrationAuthority: config.authority.publicKey,
      }).rpc();
      record = await store.patch(key, { phase: "begun", error: undefined });
      curve = await (program.account as any).curve.fetch(curvePublicKey) as CurveData;
    }

    if (curve.status === 2) {
      const authorityTokenAccount = getAssociatedTokenAddressSync(mint, config.authority.publicKey);
      await program.methods.withdrawMigrationAssets().accounts({
        global: globalPda,
        curve: curvePublicKey,
        mint,
        tokenVault: curve.tokenVault,
        migrationAuthority: config.authority.publicKey,
        authorityTokenAccount,
        tokenProgram: TOKEN_PROGRAM_ID,
        associatedTokenProgram: ASSOCIATED_TOKEN_PROGRAM_ID,
        systemProgram: SystemProgram.programId,
      }).rpc();
      curve = await (program.account as any).curve.fetch(curvePublicKey) as CurveData;
      record = await store.patch(key, {
        phase: "withdrawn",
        withdrawnSol: curve.withdrawnSolAmount.toString(),
        withdrawnTokens: curve.withdrawnTokenAmount.toString(),
        error: undefined,
      });
    }

    if (curve.status !== 3) return;
    const withdrawnSol = BigInt(curve.withdrawnSolAmount.toString());
    const withdrawnTokens = BigInt(curve.withdrawnTokenAmount.toString());
    if (withdrawnSol <= config.solReserveLamports) {
      throw new Error(`Withdrawn SOL ${withdrawnSol} is not enough after reserving ${config.solReserveLamports}`);
    }

