          record = await store.patch(key, {
            phase: "swap-submitted",
            swapInput: swapInput.toString(),
            preSwapCoreBalance: preSwapCoreBalance.toString(),
            quotedCoreAmount: prepared.quotedCoreAmount.toString(),
            signedSwapTransaction: prepared.signedTransaction,
            jupiterRequestId: prepared.requestId,
            lastValidBlockHeight: prepared.lastValidBlockHeight,
            swapSignature: prepared.signature,
            error: undefined,
          });
        }

